var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......이, 이겼나?","JPN":"……か、勝った？","ENG":"...Did we win?","TWN":"……贏、贏了嗎？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"핫! 큰소리 뻥뻥 치더니 별것도 아니잖아!","JPN":"ふん！　あんなに大口たたいといて、大したことないじゃんか！","ENG":"Ha! She was all talk and had nothing to show for it!","TWN":"哼！說了那麼多大話，也沒有什麼了不起的嘛！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"다들 방심하지 마!","JPN":"みんな、油断しないで！","ENG":"Don't let down your guards!","TWN":"大家不要掉以輕心！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"놈은 리플레이서 최고 간부 중의 한 명이야! 이 정도로 끝났을 리가 없어!","JPN":"奴はリプレイサーの最高幹部の1人よ！　この程度で済むはずがない！","ENG":"She's one of the highest ranking Replacers! There's no way she went down that easily!","TWN":"那傢伙是克隆集團的最高層幹部之一！不可能就這樣結束的！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"하, 하지만 그 공격을 맞고도 멀쩡할 리가......","JPN":"で、でも、さっきの攻撃を受けて何ともないはずが……","ENG":"But there's no way she survived that attack...","TWN":"但、但是受到那種攻擊，不可能會平安無事……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"엎드려!","JPN":"伏せて！","ENG":"Get down!","TWN":"趴下！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐, 뭐가 날아온 거야?","JPN":"なに、何が飛んできたの？","ENG":"W-what the heck was that?","TWN":"有、有什麼飛過來了？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......말했잖아? 그렇게 쉽게 끝날 상대가 아니라고.","JPN":"……言ったでしょ？　そう簡単に終わる相手じゃないって。","ENG":"I told you... There's no way she'd go down so easily.","TWN":"……不是說了嗎？ 不是那麼輕易就能了結的對手。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"......조금 놀려줄까 했는데, 미완성품치고는 눈치가 빠르군.","JPN":"……ちょっとからかってやろうと思ったけど、未完成品にしては勘がいいな。","ENG":"I was going to toy with you for a while... But you're sharper than I thought.","TWN":"……本來還想跟你們玩一玩的，但作為未完成品，妳的觀察力還挺不錯的嘛。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"이래서야 전투의 흥이 깨지잖아?","JPN":"これじゃあ、戦闘の熱が冷めてしまうだろ？","ENG":"What a buzzkill.","TWN":"這不就破壞了戰鬥的興致嗎？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"머, 멀쩡하다고......?","JPN":"む、無傷……？","ENG":"She... She's completely unharmed...?","TWN":"竟然……毫髮無傷……？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"아...... 아아......","JPN":"ああ……","ENG":"Uh... Uhhh...","TWN":"啊……啊啊……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"역시...... 만만하진 않네.","JPN":"やっぱり、そう簡単にはいかないのね。","ENG":"Of course... This is no cakewalk, after all.","TWN":"果然……沒有這麼容易呢。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"그래도 뭐, 제법이라는 건 인정해야겠어.","JPN":"でもまあ、なかなかの腕だな。　認めてやろう。","ENG":"But I've got to hand it to you. I'm impressed.","TWN":"即使如此，我也得承認你們還挺像樣的。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"최근에 겪은 전투들 중에는 가장 손맛이 있는 편이었거든.","JPN":"最近経験した戦闘の中では、一番手応えがある方だからな。","ENG":"That was the most exciting battle I've had in while.","TWN":"在最近經歷過的戰鬥中，這算是最有手感的一次了。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"하지만...... 장난은 여기까지 해 두지.","JPN":"でも……お遊びはここまでにしよう。","ENG":"But... Playtime is over.","TWN":"不過……玩笑就到此為止吧。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"시간을 너무 지체하면 귀찮은 일이 많아질 테니까.","JPN":"時間をかけすぎると、面倒ごとが増えるからな。","ENG":"Stalling any further will only lead to unnecessary complications.","TWN":"時間要是拖太晚，麻煩的事情會變多的。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"이제부턴 조금 진지하게 상대를......","JPN":"ここからはもう少し真剣に相手して……","ENG":"It's time to get serious...","TWN":"我就稍微認真地來當你們的對手吧……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......찾았다. 이 망할 자식.","JPN":"……見つけた。このクズ野郎。","ENG":"...Found you. You scumbag.","TWN":"……找到妳了。妳這混蛋。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};